local function au(pt, pu)
	local Z = pu
	local be = Z.Children
	local ni = Z.Parent
	local pv = Instance.new(pt)
	for pw, d3 in pairs(pu) do
		if pw ~= "Children" and pw ~= "Parent" then
			local dv = pv
			local px = dv[pw]
			if typeof(px) == "RBXScriptSignal" then
				px:Connect(d3)
			else
				pv[pw] = d3
			end
		end
	end
	if be then
		for ev, fo in ipairs(be) do
			fo.Parent = pv
		end
	end
	pv.Parent = ni
	return pv
end
return au
